INSERT INTO cursos (id_curso, nombre_curso, descripcion_curso, gratuito, duracion_horas, activo)
VALUES
(1, 'Historia Diplomática de México', 'Análisis de los eventos y tratados clave en la historia diplomática y relaciones exteriores de México desde la independencia hasta la era contemporánea.', true, 40, true),
(2, 'Derecho Internacional Público', 'Estudio de los principios, normas y tratados que regulan el comportamiento de los Estados y otros sujetos internacionales.', true, 60, true),
(3, 'Política Exterior Multilateral', 'Análisis profundo sobre el rol de México en organismos internacionales como la ONU, OEA y foros globales.', true, 30, true),
(4, 'Protocolo y Etiqueta Diplomática', 'Reglas, costumbres y ceremonial aplicables en las relaciones internacionales y eventos oficiales de alto nivel.', true, 20, true),
(5, 'Relaciones Bilaterales México - EE.UU.', 'Estudio exhaustivo de la relación diplomática, comercial y de seguridad más importante y compleja para el Estado mexicano.', true, 50, true),
(6, 'Economía Política Internacional', 'Intersección entre economía y política a nivel global. Tratados de libre comercio, aranceles y organismos financieros.', true, 45, true),
(7, 'Organismos Internacionales y Gobernanza Global', 'Estructura, funcionamiento y toma de decisiones en la gobernanza global post-Segunda Guerra Mundial.', true, 35, true),
(8, 'Derecho Consular y Protección a Mexicanos', 'Normativa y práctica consular. Asistencia y protección de connacionales en el extranjero según la Convención de Viena.', true, 55, true),
(9, 'Negociación y Mediación de Conflictos', 'Técnicas, tácticas y estrategias de negociación aplicadas a controversias internacionales.', true, 25, true),
(10, 'Cooperación Internacional para el Desarrollo', 'Mecanismos y fondos de asistencia técnica, científica y financiera entre Estados y la AMEXCID.', true, 30, true)
INSERT INTO preguntas (id_curso, leccion, planteamiento, pregunta, opciones, respuesta_correcta, explicacion, referencia)
VALUES
(1, 1, 'Tratados del S. XIX', '¿Qué tratado puso fin a la guerra entre EE. UU. y México (1846-1848)?', '{"A": "Tratado de McLane-Ocampo", "B": "Tratado de Guadalupe Hidalgo", "C": "Tratados de Córdoba", "D": "Tratado de Velasco"}', 'B', 'El Tratado de Guadalupe Hidalgo resultó en la pérdida de la mitad del territorio.', 'Historia de las Relaciones Internacionales.'),
(1, 1, 'Doctrinas Históricas', '¿Qué doctrina mexicana establece la no intervención y el no reconocimiento de gobiernos extranjeros?', '{"A": "Doctrina Castañeda", "B": "Doctrina Carranza", "C": "Doctrina Estrada", "D": "Doctrina Juárez"}', 'C', 'La Doctrina Estrada (1930) establece que México no juzgará los cambios de gobierno de otras naciones.', 'SRE.'),
(1, 2, 'Conflictos con Europa', '¿Qué país europeo llevó a cabo la "Guerra de los Pasteles" (1838)?', '{"A": "España", "B": "Inglaterra", "C": "Alemania", "D": "Francia"}', 'D', 'Primer conflicto bélico entre México y Francia por reclamaciones de ciudadanos franceses.', 'Historia de México.'),
(1, 2, 'Guerra de Reforma', 'Tratado firmado por el gobierno conservador en 1859 para buscar apoyo de España.', '{"A": "McLane-Ocampo", "B": "Mon-Almonte", "C": "Gadsden", "D": "La Soledad"}', 'B', 'El Tratado Mon-Almonte fue firmado por el bando conservador con España durante la Guerra de Reforma.', 'Diplomacia del S. XIX.'),
(1, 3, 'Revolución Mexicana', 'Incidente diplomático de 1914 que provocó la ocupación estadounidense de un puerto mexicano.', '{"A": "Incidente de Tampico", "B": "Invasión a Columbus", "C": "Telegrama Zimmermann", "D": "Decena Trágica"}', 'A', 'Llevó a la ocupación militar de Veracruz por fuerzas de EE. UU.', 'Revolución y Política Exterior.'),
(2, 1, 'Fuentes del DIP', 'Según el Art. 38 del Estatuto de la CIJ, ¿cuál no es fuente principal?', '{"A": "Convenciones Internacionales", "B": "Costumbre Internacional", "C": "Jurisprudencia y doctrina", "D": "Principios generales"}', 'C', 'La jurisprudencia y doctrina son medios auxiliares, no fuentes primarias.', 'Estatuto CIJ.'),
(2, 1, 'Tratados', '¿Qué principio consagra el artículo 26 de la Convención de Viena de 1969?', '{"A": "Jus Cogens", "B": "Pacta sunt servanda", "C": "Rebus sic stantibus", "D": "Res inter alios acta"}', 'B', 'Pacta sunt servanda significa que todo tratado en vigor obliga a las partes a cumplirlo de buena fe.', 'Convención de Viena 1969.'),
(2, 2, 'Responsabilidad del Estado', 'Elemento esencial para la responsabilidad internacional del Estado.', '{"A": "Hecho ilícito atribuible al Estado", "B": "Daño moral", "C": "Aprobación de la ONU", "D": "Declaración de guerra"}', 'A', 'Hecho internacionalmente ilícito atribuible a un Estado y que viola una obligación.', 'CDI - Responsabilidad Estado.'),
(2, 3, 'Jus Cogens', 'Norma imperativa de derecho internacional general que no admite acuerdo en contrario.', '{"A": "Soft Law", "B": "Jus dispositivo", "C": "Jus Cogens", "D": "Lex ferenda"}', 'C', 'Ejemplos: prohibición de la esclavitud, tortura o genocidio.', 'Derecho Internacional Público.'),
(2, 3, 'Sujetos', 'Tienen capacidad limitada y derivada en el DIP.', '{"A": "Estados", "B": "Individuos", "C": "Organizaciones Internacionales", "D": "ONGs"}', 'C', 'Su personalidad es derivada del tratado constitutivo firmado por Estados.', 'Seara Vázquez.'),
(3, 1, 'ONU', '¿Cuántos miembros permanentes tiene el Consejo de Seguridad de la ONU?', '{"A": "3", "B": "5", "C": "10", "D": "15"}', 'B', 'EE.UU., Rusia, China, Francia y Reino Unido.', 'Carta de la ONU.'),
(3, 1, 'Desarme', 'Tratado promovido por México (García Robles) para desnuclearizar América Latina.', '{"A": "Tratado de Tlatelolco", "B": "TNPD", "C": "Tratado de Rarotonga", "D": "Tratado de Pelindaba"}', 'A', 'Tratado de Tlatelolco (1967).', 'OPANAL.'),
(3, 2, 'OEA', 'Año de exclusión de Cuba del sistema interamericano (OEA).', '{"A": "1959", "B": "1962", "C": "1964", "D": "1968"}', 'B', 'En 1962, México fue el único país latinoamericano que mantuvo relaciones con Cuba.', 'Relaciones Interamericanas.'),
(3, 3, 'Derechos Humanos', 'Corte internacional encargada de juzgar violaciones a la Convención Americana sobre DH.', '{"A": "Corte de La Haya", "B": "Corte Interamericana de Derechos Humanos", "C": "Tribunal Penal Internacional", "D": "Comisión Interamericana"}', 'B', 'La Corte IDH tiene su sede en San José, Costa Rica.', 'Sistema Interamericano.'),
(3, 3, 'Medio Ambiente', 'Acuerdo multilateral climático más importante del año 2015.', '{"A": "Protocolo de Kioto", "B": "Acuerdo de París", "C": "COP21", "D": "Declaración de Río"}', 'B', 'El Acuerdo de París busca limitar el calentamiento global por debajo de 2°C.', 'Convención Marco ONU Clima.'),
(4, 1, 'Ceremonial', 'Orden de precedencia diplomática se basa principalmente en:', '{"A": "Poder económico del país", "B": "Orden alfabético del país anfitrión", "C": "Fecha y hora de presentación de cartas credenciales", "D": "Edad del embajador"}', 'C', 'El orden de precedencia suele estar determinado por la antigüedad en el cargo (fecha de presentación).', 'Convención de Viena sobre Relaciones Diplomáticas.'),
(4, 1, 'Vestimenta', 'Código de vestimenta que indica "Esmoquin" o "Tuxedo" en eventos diplomáticos.', '{"A": "White Tie", "B": "Black Tie", "C": "Business Formal", "D": "Smart Casual"}', 'B', 'Black Tie (Corbata negra) implica el uso de esmoquin.', 'Manual de Protocolo.'),
(4, 2, 'Visitas de Estado', 'Máximo nivel de visita oficial entre países.', '{"A": "Visita Oficial", "B": "Visita de Trabajo", "C": "Visita Privada", "D": "Visita de Estado"}', 'D', 'Reservada para Jefes de Estado y conlleva máximos honores militares y cenas de gala.', 'Práctica Diplomática.'),
(4, 2, 'Cartas Credenciales', 'Documento que el nuevo Embajador entrega al Jefe de Estado receptor.', '{"A": "Exequátur", "B": "Plácet", "C": "Cartas Credenciales", "D": "Nota Verbal"}', 'C', 'Acto solemne mediante el cual el embajador asume plenamente sus funciones.', 'SRE Ceremonial.'),
(4, 3, 'Comunicaciones', 'Comunicación diplomática de tercera persona, sin firma, usando sello diplomático.', '{"A": "Nota firmada", "B": "Nota Verbal", "C": "Ayuda Memoria", "D": "Memorándum"}', 'B', 'La Nota Verbal es el instrumento más común de correspondencia formal entre embajadas y cancillerías.', 'Derecho Diplomático.'),
(5, 1, 'Comercio', 'Acuerdo trilateral que sustituyó al TLCAN en 2020.', '{"A": "TLCAN 2.0", "B": "T-MEC", "C": "ALCA", "D": "CAFTA"}', 'B', 'El Tratado entre México, EE. UU. y Canadá (T-MEC).', 'Secretaría de Economía.'),
(5, 1, 'Conflictos Históricos', 'Territorio en disputa resuelto en 1963.', '{"A": "El Chamizal", "B": "Isla Clipperton", "C": "La Mesilla", "D": "Isla de Roatán"}', 'A', 'Disputa territorial entre El Paso y Ciudad Juárez devuelta a México pacíficamente.', 'SRE El Chamizal.'),
(5, 2, 'Migración', 'Programa bilateral (1942-1964) de trabajo temporal agrícola.', '{"A": "Programa Paisano", "B": "Programa Fronterizo", "C": "Programa Bracero", "D": "Programa DACA"}', 'C', 'Brindó mano de obra mexicana a EE.UU. durante y después de la WWII.', 'Historia de la Migración.'),
(5, 3, 'Seguridad', 'Iniciativa bilateral de cooperación en seguridad impulsada en 2008.', '{"A": "Plan Colombia", "B": "Iniciativa Mérida", "C": "Entendimiento Bicentenario", "D": "Operación Rápido y Furioso"}', 'B', 'La Iniciativa Mérida fue firmada bajo los gobiernos de Calderón y Bush.', 'Relaciones Bilaterales.'),
(5, 3, 'Agua', 'Tratado que regula la distribución de aguas de los ríos Colorado, Tijuana y Bravo.', '{"A": "Tratado de 1944", "B": "Tratado de Aguas de 1906", "C": "Convenio de La Paz", "D": "Tratado de Guadalupe Hidalgo"}', 'A', 'El Tratado de Aguas de 1944 rige actualmente los compromisos hídricos.', 'CILA.'),
(6, 1, 'Bretton Woods', 'Institución creada en 1944 para otorgar préstamos a países con crisis de balanza de pagos.', '{"A": "Banco Mundial", "B": "Fondo Monetario Internacional (FMI)", "C": "OMC", "D": "OCDE"}', 'B', 'El FMI se enfoca en la estabilidad macroeconómica global.', 'Sistema Bretton Woods.'),
(6, 1, 'GATT', 'Antecesor directo de la Organización Mundial del Comercio.', '{"A": "GATT", "B": "CEPAL", "C": "UNCTAD", "D": "Acuerdo de Marrakesh"}', 'A', 'Acuerdo General sobre Aranceles Aduaneros y Comercio (GATT).', 'Historia OMC.'),
(6, 2, 'Comercio Mexicano', 'Año en que México ingresó al GATT.', '{"A": "1947", "B": "1986", "C": "1994", "D": "2000"}', 'B', 'El ingreso al GATT en 1986 marcó la apertura económica de México.', 'Política Comercial Mexicana.'),
(6, 3, 'Inversión', 'Tratados diseñados para proteger y promover flujos de inversión extranjera directa.', '{"A": "TLCs", "B": "APPRI", "C": "Acuerdos Marco", "D": "Memorándum de Entendimiento"}', 'B', 'Los Acuerdos para la Promoción y Protección Recíproca de las Inversiones (APPRI).', 'Derecho Económico.'),
(6, 3, 'Integración', 'Nivel máximo de integración económica.', '{"A": "Zona de libre comercio", "B": "Unión aduanera", "C": "Mercado común", "D": "Unión económica y monetaria"}', 'D', 'Ejemplo: Zona Euro.', 'Teoría de la Integración.'),
(7, 1, 'OCDE', 'Foro de los países con economías avanzadas. ¿Cuándo ingresó México?', '{"A": "1994", "B": "1986", "C": "2000", "D": "2010"}', 'A', 'México fue el primer país latinoamericano en ingresar a la OCDE en 1994.', 'OCDE.'),
(7, 1, 'G20', 'Mecanismo de gobernanza económica surgido tras crisis financieras. ¿México es miembro?', '{"A": "No, sólo del G7", "B": "Sí, como economía emergente", "C": "Es miembro observador", "D": "Fue expulsado"}', 'B', 'México es miembro fundador del G20 a nivel de líderes (1999/2008).', 'G20.'),
(7, 2, 'Gobernanza Sanitaria', 'Organismo especializado de la ONU en salud.', '{"A": "UNICEF", "B": "OMS", "C": "OIT", "D": "PNUD"}', 'B', 'Organización Mundial de la Salud.', 'Sistema de la ONU.'),
(7, 3, 'Gobernanza Ambiental', 'El PNUMA tiene su sede principal en:', '{"A": "Ginebra", "B": "Nueva York", "C": "Nairobi", "D": "Viena"}', 'C', 'Kenia alberga la sede del Programa de la ONU para el Medio Ambiente.', 'Medio Ambiente ONU.'),
(7, 3, 'Foros Regionales', 'Mecanismo de diálogo político y cooperación exclusivo de América Latina y el Caribe.', '{"A": "OEA", "B": "MERCOSUR", "C": "CELAC", "D": "Alianza del Pacífico"}', 'C', 'Comunidad de Estados Latinoamericanos y Caribeños (CELAC).', 'Foros Regionales.'),
(8, 1, 'Convención', 'Tratado que rige las relaciones consulares.', '{"A": "Convención de Viena 1961", "B": "Convención de Viena 1963", "C": "Convención de Ginebra", "D": "Estatuto de Roma"}', 'B', 'Convención de Viena sobre Relaciones Consulares de 1963.', 'DIP.'),
(8, 1, 'Exequátur', 'Documento mediante el cual el Estado receptor autoriza a un cónsul a ejercer sus funciones.', '{"A": "Plácet", "B": "Cartas Patentes", "C": "Exequátur", "D": "Salvoconducto"}', 'C', 'Sin exequátur, el jefe de oficina consular no puede iniciar funciones.', 'CVRC 1963.'),
(8, 2, 'Caso Avena', 'Histórico fallo de la Corte Internacional de Justicia a favor de México por violación del derecho a la notificación consular en:', '{"A": "Francia", "B": "Reino Unido", "C": "Estados Unidos", "D": "Canadá"}', 'C', 'Caso Avena y otros nacionales mexicanos (2004) contra EE. UU.', 'Jurisprudencia CIJ.'),
(8, 3, 'Funciones', '¿El Cónsul representa políticamente a su Estado ante el gobierno central del Estado receptor?', '{"A": "Sí, es su principal función", "B": "No, esa es función del Embajador", "C": "Sí, sólo si no hay embajada", "D": "Depende de la visa"}', 'B', 'La representación política / diplomática corresponde a la Embajada (Jefe de Misión).', 'Derecho Consular.'),
(8, 3, 'Protección', 'Documento de viaje emitido a connacionales sin pasaporte en casos de emergencia.', '{"A": "Visado de cortesía", "B": "Pasaje libre", "C": "Pasaporte de Protección / OP7", "D": "Matrícula Consular"}', 'C', 'El pasaporte de emergencia o documento de identidad para el retorno.', 'SRE Consular.'),
(9, 1, 'Teoría M.A.A.N.', 'En el Método Harvard, M.A.A.N. significa:', '{"A": "Mejor Alternativa a un Acuerdo Negociado", "B": "Máxima Aptitud para el Acuerdo Nacional", "C": "Mecanismo Alterno de Acción Negociada", "D": "Mejor Acción Ante una Negativa"}', 'A', 'El BATNA (MAAN en español) es la carta de fuerza de un negociador.', 'Fisher y Ury.'),
(9, 1, 'Posturas vs Intereses', 'El enfoque principal del modelo integrativo de negociación es:', '{"A": "Atacar la postura del oponente", "B": "Centrarse en los intereses, no en las posiciones", "C": "Ceder siempre para mantener la relación", "D": "Ganancia suma cero"}', 'B', 'Separar a las personas del problema y buscar intereses subyacentes comunes.', 'Resolución de Conflictos.'),
(9, 2, 'Mediación Inter.', 'La diferencia principal entre mediación y arbitraje:', '{"A": "La mediación es privada, el arbitraje público", "B": "El mediador facilita el acuerdo, el árbitro dicta un laudo vinculante", "C": "No hay diferencia legal", "D": "La mediación es sólo para Estados"}', 'B', 'El árbitro decide (falla), el mediador solo acerca a las partes.', 'MASC.'),
(9, 3, 'Caso Contadora', 'Grupo impulsado por México en los 80s para pacificar:', '{"A": "Tierra del Fuego", "B": "Medio Oriente", "C": "Centroamérica", "D": "El Cono Sur"}', 'C', 'El Grupo Contadora buscó la paz en los conflictos centroamericanos.', 'Historia de Mediación.'),
(9, 3, 'Tácticas', '"El policía bueno y el policía malo" es un táctica de negociación catalogada como:', '{"A": "Colaborativa", "B": "Competitiva/Dura", "C": "Evasiva", "D": "Acomodaticia"}', 'B', 'Busca crear presión psicológica sobre la contraparte para que ceda.', 'Tácticas de Negociación.'),
(10, 1, 'AMEXCID', 'Agencia Mexicana de Cooperación Internacional para el Desarrollo fue creada en:', '{"A": "1994", "B": "2000", "C": "2011", "D": "2018"}', 'C', 'Promulgada tras la Ley de Cooperación Internacional para el Desarrollo (2011).', 'SRE/AMEXCID.'),
(10, 1, 'Cooperación Sur-Sur', 'Tipo de cooperación que México ejerce principalmente hacia:', '{"A": "Europa del Este", "B": "América Latina y el Caribe", "C": "América del Norte", "D": "Escandinavia"}', 'B', 'Esquema de horizontalidad y beneficio mutuo entre países en vías de desarrollo.', 'Relaciones Internacionales.'),
(10, 2, 'Modalidades', 'Cooperación en la cual dos países en desarrollo son apoyados financieramente por un país desarrollado u organismo.', '{"A": "Bilateral pura", "B": "Cooperación Norte-Sur", "C": "Cooperación Triangular", "D": "Multilateral cerrada"}', 'C', 'Ej. México y Alemania cooperando conjuntamente en un país de Centroamérica.', 'Tipos de Cooperación.'),
(10, 3, 'ODS', 'Objetivos de Desarrollo Sostenible (Agenda 2030) contemplan cuántos objetivos:', '{"A": "10", "B": "15", "C": "17", "D": "20"}', 'C', 'La agenda incluye 17 objetivos globales adoptados en 2015.', 'Sistema ONU.'),
(10, 3, 'Fondos Mixtos', 'Países con los cuales México tiene fondos conjuntos de cooperación relevantes y activos:', '{"A": "Alemania y Rusia", "B": "Chile y Uruguay", "C": "Japón y China", "D": "EE.UU. y Reino Unido"}', 'B', 'Existen Fondos Conjuntos de Cooperación consolidados con Chile y Uruguay.', 'Política de Estado.')
